if (typeof globalThis.DOMMatrix === 'undefined') {
    globalThis.DOMMatrix = class DOMMatrix {
        constructor(init) {
            const v = init && Array.isArray(init) ? init : [1, 0, 0, 1, 0, 0];
            this.a = v[0]; this.b = v[1]; this.c = v[2];
            this.d = v[3]; this.e = v[4]; this.f = v[5];
            this.m11 = v[0]; this.m12 = v[1]; this.m21 = v[2];
            this.m22 = v[3]; this.m41 = v[4]; this.m42 = v[5];
            this.is2D = true; this.isIdentity = (v[0] === 1 && v[1] === 0 && v[2] === 0 && v[3] === 1 && v[4] === 0 && v[5] === 0);
        }
        inverse() { return new DOMMatrix([1, 0, 0, 1, 0, 0]); }
        multiply(o) { return new DOMMatrix([this.a, this.b, this.c, this.d, this.e, this.f]); }
        transformPoint(p) { return { x: p?.x || 0, y: p?.y || 0 }; }
        static fromMatrix(o) { return new DOMMatrix([o?.a || 1, o?.b || 0, o?.c || 0, o?.d || 1, o?.e || 0, o?.f || 0]); }
        static fromFloat64Array(a) { return new DOMMatrix(Array.from(a || [])); }
        static fromFloat32Array(a) { return new DOMMatrix(Array.from(a || [])); }
    };
}
