                async function gerarAttpQuote(texto) {
                    var txt = String(texto)
                        .replace(/\s*\|\s*/g, "\n")
                        .trim();

                    var body = {
                        type: "quote",
                        format: "png",
                        backgroundColor: "#ffffff",
                        width: 512,
                        height: 512,

                        // quanto maior = texto maior
                        scale: 9,

                        messages: [
                            {
                                entities: [],
                                avatar: false,
                                from: {
                                    id: 1,
                                    name: "" // вҶҗ remove o "ATTP" de cima
                                },
                                text: txt,
                                replyMessage: {}
                            }
                        ]
                    };

                    var res = await axios.post(
                        "https://bot.lyo.su/quote/generate",
                        body,
                        {
                            headers: { "Content-Type": "application/json" },
                            timeout: 20000
                        }
                    );

                    return Buffer.from(res.data.result.image, "base64");
                }

                async function baixarMp4Buffer(url) {
                    var r = await axios.get(url, {
                        responseType: "arraybuffer",
                        timeout: 120000, // 2 min
                        maxRedirects: 5,
                        headers: { "User-Agent": "Mozilla/5.0" },
                        validateStatus: (s) => s >= 200 && s < 400,
                        maxContentLength: Infinity,
                        maxBodyLength: Infinity
                    });

                    var ct = String(r.headers?.["content-type"] || "");
                    // se vier html, nГЈo Г© mp4 direto
                    if (ct.includes("text/html")) return null;

                    return Buffer.from(r.data);
                }

