                // ============ IA AUTOMГҒTICA - RESPONDE @MENГҮГғO E REPLY ============
                var botNumberAI = corvo.user.id.split(':')[0] + '@s.whatsapp.net';
                var botLidAI = (corvo?.user?.lid?.split(':')[0] || '') + '@lid';

