                                msg += `в•ҺвҷұЛ– в–ё бҙ„бҙҸбҙҚбҙҖЙҙбҙ…бҙҸ КҖбҙҮбҙҖКҹ\nв•ҺвҶі *${prefix + item.comandoOriginal}*\n`;
