                                fs.writeFileSync(`./DADOS DO CORVO/INFO_CORVO/media/nescessario.json`, JSON.stringify(nescessario, null, 2) + "\n");

                                reply(`*бҙҸ КҖбҙҮбҙ„бҙңКҖsбҙҸ Т“бҙҸЙӘ бҙ…бҙҮsбҙҖбҙӣЙӘбҙ бҙҖбҙ…бҙҸ бҙ„бҙҸбҙҚ sбҙңбҙ„бҙҮssбҙҸ рҹҷ…вҖҚвҷӮпёҸ*`)
