                            var [horas, minutos] = barra.split(':');
                            if (!horas || !minutos) return reply('*КңбҙҸКҖбҙҖКҖЙӘбҙҸ ЙӘЙҙбҙ„бҙҸбҙҚбҙҳКҹбҙҮбҙӣбҙҸ, бҙңкңұбҙҮ КңКң:бҙҚбҙҚ* вҡ пёҸ');
                            if (isNaN(horas) || isNaN(minutos)) return reply('*бҙңкңұбҙҮ бҙҖбҙҳбҙҮЙҙбҙҖкңұ ЙҙбҙңМҒбҙҚбҙҮКҖбҙҸкңұ ЙҙбҙҸ КңбҙҸКҖбҙҖКҖЙӘбҙҸ* рҹ”ў');

                            horas = horas.padStart(2, '0');
                            minutos = minutos.padStart(2, '0');

                            if (parseInt(horas) > 23 || parseInt(minutos) > 59) return reply('*КңбҙҸКҖбҙҖМҒКҖЙӘбҙҸ ЙӘЙҙбҙ бҙҖМҒКҹЙӘбҙ…бҙҸ* вқҢ');

                            var horarioFinal = `${horas}:${minutos}:00`;
                            definirFechamento(from, horarioFinal);

                            await reply(`*рҹ”’ бҙҸ ЙўКҖбҙңбҙҳбҙҸ кңұбҙҮКҖбҙҖМҒ кң°бҙҮбҙ„КңбҙҖбҙ…бҙҸ aМҖкңұ ${horarioFinal}* вҸі\n-\n*кңұбҙҮбҙҠбҙҖбҙҚ КҷбҙҮбҙҚ-бҙ ЙӘЙҙбҙ…бҙҸкңұ бҙҖбҙҸ бҙ„бҙҖбҙҸкңұ бҙҸКҖЙўбҙҖЙҙЙӘбҙўбҙҖбҙ…бҙҸ бҙҳбҙҸКҖ бҙҚЙӘбҙҚ...* рҹ’ҒвҖҚвҷӮпёҸ`);

