                            (senderNum && permitidosNums.includes(senderNum)) ||
                            (senderRawNum && permitidosLidNums.includes(senderRawNum))

                        if (!autorizado) return reply("*vocГӘ nГЈo tem permissГЈo para usar esse comando.рҹӨ·вҖҚвҷӮпёҸ*")

                        if (!menc_os2 || menc_jid2[1]) return reply("*рҹҢҹ mencione a mensagem ou marque um usuГЎrio com @*")
                        if (!JSON.stringify(groupMembers).includes(menc_os2)) return reply("*este usuГЎrio saiu do grupo ou foi removido рҹӨ·вҖҚвҷӮпёҸ*")

                        var fotoPerfilUser;
                        try { fotoPerfilUser = await corvo.profilePictureUrl(encontrarJidReal(menc_os2), 'image'); }
