                            if (!Number.isFinite(limit)) limit = 1;

                            if (limit > 5) limit = 5;
                            if (limit < 1) limit = 1;

                            // nocache pra evitar retorno repetido
                            var url = `https://systemzone.store/api/pinterest?q=${encodeURIComponent(query)}&limit=50&_=${Date.now()}`;

                            var { data } = await axios.get(url);

                            if (!data?.status || !Array.isArray(data?.results) || data.results.length === 0) {
                                return corvo.sendMessage(from, { text: "вқҢ Nenhuma imagem encontrada." }, { quoted: selo });
                            }

                            // pega URL da imagem e remove duplicadas
                            var unique = [];
                            var seen = new Set();

                            for (var item of data.results) {
                                var imgUrl = item?.image_url || item?.url || item?.image;
                                if (!imgUrl) continue;
                                if (seen.has(imgUrl)) continue;
                                seen.add(imgUrl);
                                unique.push(imgUrl);
                            }

                            if (unique.length === 0) {
                                return corvo.sendMessage(from, { text: "вқҢ Nenhuma imagem vГЎlida encontrada." }, { quoted: selo });
                            }

                            // embaralha pra nГЈo repetir sempre a mesma
                            unique.sort(() => Math.random() - 0.5);

                            var results = unique.slice(0, Math.min(limit, unique.length));

                            await corvo.sendMessage(from, {
                                text: `рҹ“Ң *Pinterest*\nрҹ”Қ Pesquisa: *${query}*\nрҹ–јпёҸ Enviando: ${results.length}`
                            }, { quoted: selo });

                            for (var imgUrl of results) {
                                await corvo.sendMessage(from, {
                                    image: { url: imgUrl },
                                    caption: `рҹ“Ң ${query}`
                                }, { quoted: selo });
                            }

