                        if (fs.existsSync(`./DADOS DO CORVO/grupos/games/enigma/${from}.json`)) return reply("NГЈo existe nenhuma partida atual do jogo neste grupo.");
                        var eni1 = JSON.parse(fs.readFileSync(`./DADOS DO CORVO/grupos/games/enigma/${from}.json`))
