                        var grupo = RG_SCOINS.find(g => g.grupo === from) || { chances: { minerar: 0, cassino: 0 } };
                        if (!grupo) return reply('*ЙҙбҙҖбҙҸ КңбҙҖ ЙҙЙӘЙҙЙўбҙңбҙҮбҙҚ бҙ„бҙҸбҙҚ N-бҙ„бҙҸЙӘЙҙs ЙҙбҙҮsбҙӣбҙҮ ЙўКҖбҙңбҙҳбҙҸ рҹӨ·вҖҚвҷӮпёҸ*');
                        var rank = grupo.usus.sort((a, b) => b.coins - a.coins).slice(0, 10);
