                                    text += `в”Ӯ рҹ’° PreГ§o: ${price.toLocaleString()}\n`;
                                    text += `в”Ӯ рҹ“Ҡ VocГӘ tem: ${owned}\n`;
                                    text += `в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n\n`;
