                            text += `вң… AГ§Гөes vendidas!\n\n`;
                            text += `рҹ“Ҡ AГ§ГЈo: ${stockType.toUpperCase()}\n`;
                            text += `рҹ“Ҳ Quantidade: ${amount}\n`;
                            text += `рҹ’° Recebido: ${totalValue.toLocaleString()}\n`;
                            text += `рҹ’ј Lucro total: ${me.investments.totalProfit.toLocaleString()}`;

                            saveEconomy(econ);
